#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int Q;
    scanf("%d", &Q);
    int *arr = (int*)malloc(Q * sizeof(int));
    int size = 0;
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int Z;
            scanf("%d", &Z);
            arr[size] = Z;
            size++;
        } else if (type == 2) {
            int X;
            scanf("%d", &X);
            for (int j = X - 1; j < size - 1; j++) {
                arr[j] = arr[j + 1];
            }
            size--;
        } else if (type == 3) {
            int X, Z;
            scanf("%d %d", &X, &Z);
            arr[X - 1] = Z;
        } else if (type == 4) {
            int L, R, K;
            scanf("%d %d %d", &L, &R, &K);
            int *temp = (int*)malloc((R - L + 1) * sizeof(int));
            for (int j = L - 1; j < R; j++) {
                temp[j - L + 1] = arr[j];
            }
            qsort(temp, R - L + 1, sizeof(int), compare);
            printf("%d\n", temp[K - 1]);
            free(temp);
        }
    }
    free(arr);
    return 0;
}

