import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int Q = sc.nextInt();
        int[] arr = new int[Q];
        int size = 0;
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            if (type == 1) {
                int Z = sc.nextInt();
                arr[size] = Z;
                size++;
            } else if (type == 2) {
                int X = sc.nextInt();
                for (int j = X - 1; j < size - 1; j++) {
                    arr[j] = arr[j + 1];
                }
                size--;
            } else if (type == 3) {
                int X = sc.nextInt();
                int Z = sc.nextInt();
                arr[X - 1] = Z;
            } else if (type == 4) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int K = sc.nextInt();
                int[] temp = new int[R - L + 1];
                for (int j = L - 1; j < R; j++) {
                    temp[j - L + 1] = arr[j];
                }
                Arrays.sort(temp);
                System.out.println(temp[K - 1]);
            }
        }
    }
}

