const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
let arr = [];
while (idx < lines.length) {
    let query = lines[idx].trim().split(' ');
    if (query[0] == '1') {
        let Z = parseInt(query[1]);
        arr.push(Z);
    } else if (query[0] == '2') {
        let X = parseInt(query[1]);
        arr.splice(X - 1, 1);
    } else if (query[0] == '3') {
        let X = parseInt(query[1]);
        let Z = parseInt(query[2]);
        arr[X - 1] = Z;
    } else if (query[0] == '4') {
        let L = parseInt(query[1]);
        let R = parseInt(query[2]);
        let K = parseInt(query[3]);
        let temp = arr.slice(L - 1, R).sort((a, b) => a - b);
        console.log(temp[K - 1]);
    }
    idx++;
}
